import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Creating a fixed-size buffer
        int bufferSize = 10;
        char[] buffer = new char[bufferSize];

        // Copying user input into the fixed-size buffer with proper bounds checking
        for (int i = 0; i < Math.min(input.length(), bufferSize); i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Input safely copied to the buffer!");
    }
}

